marks = int(input('Enter marks: '))

# if-elif-else
if marks >= 90:
    grade = 'A'
elif marks >= 80:
    grade = 'B'
elif marks >= 60:
    grade = 'C'
else:
    grade = 'F'

print(f'Grade: {grade}')

# Ternary (short if-else)
status = 'Pass' if marks >= 60 else 'Fail'
print(status)

# Nested if
age = 20
has_id = True
if age >= 18:
    if has_id:
        print('Entry allowed')
    else:
        print('Show ID')
else:
    print('Too young')

# break — stop when found
numbers = [2, 4, 7, 8, 10]
for num in numbers:
    if num % 2 != 0:  # odd number found
        print(f'First odd number: {num}')  # 7
        break

# continue — skip specific items
for i in range(1, 11):
    if i % 2 == 0:    # skip even numbers
        continue
    print(i, end=' ')  # 1 3 5 7 9

# pass — placeholder
def future_feature():
    pass  # will implement later

for i in range(5):
    if i == 3:
        pass  # TODO: handle this case
    else:
        print(i, end=' ')  # 0 1 2 4

# Creating sets
s1 = {1, 2, 3, 2, 1}    # duplicates removed
print(s1)                # {1, 2, 3}
s2 = set([3, 4, 5])      # from list
empty = set()            # NOT {} — that's empty dict!

# Set operations
A = {1, 2, 3, 4}
B = {3, 4, 5, 6}
print(A | B)  # Union:      {1,2,3,4,5,6}
print(A & B)  # Intersection: {3,4}
print(A - B)  # Difference:  {1,2}
print(A ^ B)  # Sym diff:    {1,2,5,6}

# Subset/Superset
print({1,2} <= {1,2,3})   # True (subset)
print({1,2,3} >= {1,2})   # True (superset)

# Add/Remove
A.add(10)       # {1,2,3,4,10}
A.discard(99)   # no error even though 99 not in A
A.remove(1)     # removes 1, KeyError if not present

d = {'a': 1, 'b': 2, 'c': 3}

# Removing
val = d.pop('a')        # removes 'a', returns 1
print(val, d)           # 1 {'b':2,'c':3}
print(d.pop('z', 0))    # 0 (default, no error)

# Iterating
for key in d:                    # iterate keys
    print(key, d[key])
for k, v in d.items():           # key-value pairs (best way)
    print(f'{k}: {v}')

# Merging
d1 = {'x': 1, 'y': 2}
d2 = {'y': 99, 'z': 3}
merged = {**d1, **d2}            # d2 overrides d1 for 'y'
print(merged)  # {'x':1,'y':99,'z':3}

# Dict comprehension
scores = {'Alice': 85, 'Bob': 45, 'Carol': 92}
passed = {name: score for name, score in scores.items() if score >= 60}
print(passed)  # {'Alice': 85, 'Carol': 92}

# Basic try-except
try:
    num = int(input('Enter number: '))
    result = 100 / num
    print(f'Result: {result}')
except ValueError:
    print('Please enter a valid integer')
except ZeroDivisionError:
    print('Cannot divide by zero')
except Exception as e:
    print(f'Unexpected error: {e}')
else:
    print('No errors occurred!')   # runs if no exception
finally:
    print('This always runs')       # cleanup code

# Raise keyword
def withdraw(amount, balance):
    if amount > balance:
        raise ValueError(f'Insufficient funds. Balance: {balance}')
    return balance - amount

# Custom exception
class InvalidAgeError(Exception):
    def __init__(self, age):
        super().__init__(f'Age {age} is invalid. Must be 0-150.')
        self.age = age

def set_age(age):
    if not (0 <= age <= 150):
        raise InvalidAgeError(age)
    return age

try:
    set_age(-5)
except InvalidAgeError as e:
    print(e)  # Age -5 is invalid. Must be 0-150.

# Encapsulation
class BankAccount:
    def __init__(self, owner, balance):
        self.owner = owner
        self.__balance = balance  # private

    def deposit(self, amount):
        if amount > 0:
            self.__balance += amount

    def get_balance(self):
        return self.__balance

acc = BankAccount('Alice', 1000)
acc.deposit(500)
print(acc.get_balance())   # 1500
# print(acc.__balance)     # AttributeError — private!

# Inheritance
class Animal:
    def __init__(self, name):
        self.name = name

    def speak(self):
        return 'Some sound'

class Dog(Animal):        # inherits from Animal
    def speak(self):      # overrides parent method
        return f'{self.name} says Woof!'

class Cat(Animal):
    def speak(self):
        return f'{self.name} says Meow!'

# Polymorphism — same method, different behavior
animals = [Dog('Rex'), Cat('Whiskers'), Dog('Buddy')]
for animal in animals:
    print(animal.speak())  # calls appropriate speak()
